import{_ as i,o as t,c as l,a2 as e}from"./chunks/framework.DZrHScmQ.js";const p=JSON.parse('{"title":"Human Accountability","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/principles/human-accountability.md","filePath":"ai-native/principles/human-accountability.md"}'),n={name:"ai-native/principles/human-accountability.md"};function o(c,a,r,u,s,h){return t(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="human-accountability" tabindex="-1">Human Accountability <a class="header-anchor" href="#human-accountability" aria-label="Permalink to &quot;Human Accountability&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>责任可以被辅助，不能被外包给模型。</p><h2 id="原则" tabindex="-1">原则 <a class="header-anchor" href="#原则" aria-label="Permalink to &quot;原则&quot;">​</a></h2><ul><li>每个高影响工作流必须有人类责任人。</li><li>Agent 可以提出、执行和检查，但不能成为法律、财务或产品责任主体。</li><li>人类批准应对应真实判断，不应沦为机械点击。</li><li>责任人必须能获得足够上下文，理解自己批准的内容。</li><li>事故复盘关注系统与流程，不把“模型犯错”当作根因终点。</li></ul><h2 id="必须保留人工决策的典型场景" tabindex="-1">必须保留人工决策的典型场景 <a class="header-anchor" href="#必须保留人工决策的典型场景" aria-label="Permalink to &quot;必须保留人工决策的典型场景&quot;">​</a></h2><ul><li>不可逆或难以回滚的生产操作</li><li>权限提升与敏感数据访问</li><li>法律、合规和重大财务承诺</li><li>对外发布的高影响声明</li><li>风险模型未覆盖的新场景</li></ul>',7)])])}const _=i(n,[["render",o]]);export{p as __pageData,_ as default};
